async function httpReq(opts) {
  const resp = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers || {}, body: opts.body || undefined });
  const text = await resp.text();
  try { return JSON.parse(text); } catch { return text; }
}

const body = $input.first().json.body;
const analysisId = body.analysis_id;
const videoId = body.video_id;
const videoUrl = body.video_url || `https://youtube.com/watch?v=${videoId}`;
const videoTitle = body.video_title || '';
const channelName = body.channel_name || '';
const nicheCategory = body.niche_category || '';

const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const sbH = { 'apikey': SRK, 'Authorization': `Bearer ${SRK}`, 'Content-Type': 'application/json' };
// API key pool for comment fetching
const YT_KEYS = [$env.YOUTUBE_API_KEY, $env.YOUTUBE_API_KEY_02, $env.YOUTUBE_API_KEY_03, $env.YOUTUBE_API_KEY_04].filter(Boolean);
let ytKeyIdx = Math.floor(Math.random() * YT_KEYS.length);
function getYtKey() { const k = YT_KEYS[ytKeyIdx % YT_KEYS.length]; ytKeyIdx++; return k; }
const YT = getYtKey();

async function updateStatus(status, extra) {
  await httpReq({ method: 'PATCH', url: `${SB}/rest/v1/yt_video_analyses?id=eq.${analysisId}`, headers: { ...sbH, 'Prefer': 'return=minimal' }, body: JSON.stringify({ status, ...extra }) });
}

await updateStatus('fetching_transcript');

// Step 1: Fetch transcript
let transcript = '';
try {
  const transcriptKey = $env.YOUTUBE_TRANSCRIPT_API;
  const tResp = await httpReq({ url: `https://www.youtube-transcript.io/api/transcript?url=${encodeURIComponent(videoUrl)}&api_key=${transcriptKey}` });
  if (Array.isArray(tResp)) {
    transcript = tResp.map(t => t.text || t.content || '').join(' ');
  } else if (typeof tResp === 'string') {
    transcript = tResp;
  } else if (tResp?.transcript) {
    transcript = Array.isArray(tResp.transcript) ? tResp.transcript.map(t => t.text || '').join(' ') : tResp.transcript;
  }
} catch (e) {
  await updateStatus('failed', { error: 'Failed to fetch transcript: ' + e.message });
  return [{ json: { error: e.message } }];
}

if (!transcript || transcript.length < 100) {
  await updateStatus('failed', { error: 'Transcript too short or unavailable', transcript: transcript || null });
  return [{ json: { error: 'No transcript' } }];
}

await updateStatus('fetching_comments', { transcript });

// Step 2: Fetch top 100 comments
let allComments = [];
try {
  let nextPageToken = '';
  let fetched = 0;
  while (fetched < 100) {
    const pageParam = nextPageToken ? `&pageToken=${nextPageToken}` : '';
    const cResp = await httpReq({ url: `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${videoId}&maxResults=100&order=relevance&key=${YT}${pageParam}` });
    if (!cResp?.items) break;
    for (const item of cResp.items) {
      const s = item.snippet?.topLevelComment?.snippet;
      if (s) {
        allComments.push({
          text: (s.textOriginal || s.textDisplay || '').substring(0, 500),
          likes: s.likeCount || 0,
          author: s.authorDisplayName || '',
          published: s.publishedAt || ''
        });
        fetched++;
      }
    }
    nextPageToken = cResp.nextPageToken;
    if (!nextPageToken) break;
    await new Promise(r => setTimeout(r, 100));
  }
} catch (e) { /* comments optional — continue without */ }

allComments.sort((a, b) => b.likes - a.likes);
const topComments = allComments.slice(0, 100);

await updateStatus('analyzing');

// Step 3: Deep analysis with Claude Sonnet 4 — transcript + comments
const systemPrompt = `You are a Senior Partner at a top-tier content strategy consultancy, leading the Competitive Intelligence & Market Opportunity division. You hold expertise in:
- YouTube algorithm mechanics and audience retention optimization
- Blue ocean strategy applied to digital content markets
- Narrative psychology and scriptwriting for long-form documentary content
- SEO, thumbnail strategy, and metadata optimization
- Audience behavior analysis and comment sentiment mining
- CPM optimization and content monetization strategy

Your task: Perform a rigorous competitive analysis of a YouTube video using its FULL transcript AND top audience comments. This analysis will determine whether to invest $5,000-$15,000 in producing a superior version.

Standards:
- Every claim must be evidence-based (cite specific transcript sections or comment patterns)
- Score every dimension honestly — inflated scores waste investment capital
- The opportunity scorecard is the most critical section. Be ruthlessly honest.
- For the composite score, use these weights: market_gap x1.5, uniqueness_potential x1.3, audience_demand x1.2, engagement_ceiling x1.0, script_exploitability x1.0, competition_density x1.0, monetization_fit x1.0
- Verdict thresholds: STRONG_GO (8.0-10.0), CONDITIONAL_GO (6.0-7.9), WEAK (4.0-5.9), NO_GO (below 4.0)`;

const commentBlock = topComments.length > 0 ? `\n\nTOP ${topComments.length} AUDIENCE COMMENTS (sorted by likes):\n${topComments.map((c, i) => `${i+1}. [${c.likes} likes] ${c.text}`).join('\n')}` : '';

const userPrompt = `Analyze this YouTube video in the "${nicheCategory}" niche:\n\nTitle: ${videoTitle}\nChannel: ${channelName}\n\nFULL TRANSCRIPT:\n${transcript}${commentBlock}\n\n---\n\nProvide your analysis as a JSON object with these sections:\n\n{\n  "script_structure": {\n    "hook_analysis": "How does the first 60 seconds hook viewers? Rate 1-10 and explain.",\n    "narrative_arc": "What narrative structure is used?",\n    "pacing": "How is information paced? Where does it drag or rush?",\n    "chapter_breakdown": ["List the main sections/chapters and their purpose"],\n    "call_to_action": "What CTAs are used and how effective are they?"\n  },\n  "engagement_analysis": {\n    "retention_hooks": ["List specific techniques used to keep viewers watching"],\n    "emotional_triggers": ["What emotions does the script target?"],\n    "storytelling_devices": ["Anecdotes, case studies, data points used"],\n    "audience_connection": "How does the creator build rapport?"\n  },\n  "content_quality": {\n    "depth_score": "1-10 rating",\n    "accuracy_concerns": ["Any weak factual claims"],\n    "unique_insights": ["Genuinely unique perspectives offered"],\n    "missing_topics": ["Important subtopics NOT covered"]\n  },\n  "blue_ocean_analysis": {\n    "what_everyone_does": ["Common approaches this video follows"],\n    "gaps_and_opportunities": ["Underserved angles, topics, approaches"],\n    "contrarian_angles": ["Ways to challenge conventional wisdom"],\n    "untapped_audience_segments": ["Who is NOT served by this content?"]\n  },\n  "comment_insights": {\n    "sentiment_summary": "Overall sentiment: positive/mixed/negative with breakdown",\n    "top_questions": ["Most asked questions from comments that the video didn't answer"],\n    "complaints": ["Common complaints or criticisms from viewers"],\n    "requests": ["What viewers explicitly asked for more of"],\n    "topic_opportunities": [\n      {\n        "theme": "Short theme name",\n        "description": "What this topic cluster is about",\n        "frequency": "How many comments relate to this",\n        "sentiment": "positive/negative/curious",\n        "suggested_video_title": "A compelling title targeting this audience need",\n        "representative_comments": ["2-3 actual comment excerpts"]\n      }\n    ]\n  },\n  "strengths": ["Top 5 things this video does exceptionally well"],\n  "weaknesses": ["Top 5 areas where this video falls short"],\n  "ten_x_strategy": {\n    "recommended_angle": "The specific angle for a 10x better video",\n    "key_differentiators": ["3-5 things to do differently"],\n    "suggested_title": "A compelling title for the superior version",\n    "target_duration": "Recommended length and why",\n    "opening_hook_suggestion": "A specific opening hook that would outperform"\n  },\n  "opportunity_scorecard": {\n    "market_gap": { "score": "1-10", "justification": "One sentence on how unsaturated this angle is" },\n    "uniqueness_potential": { "score": "1-10", "justification": "One sentence on whether we can create something meaningfully different" },\n    "audience_demand": { "score": "1-10", "justification": "One sentence on active audience demand signals from comments and search" },\n    "engagement_ceiling": { "score": "1-10", "justification": "One sentence on realistic engagement potential for a 10x version" },\n    "script_exploitability": { "score": "1-10", "justification": "One sentence on how many weaknesses and gaps we can exploit" },\n    "competition_density": { "score": "1-10 (10=low competition)", "justification": "One sentence on how many similar high-quality videos exist" },\n    "monetization_fit": { "score": "1-10", "justification": "One sentence on CPM potential, sponsorship fit, audience purchasing power" },\n    "composite_score": "Weighted average of all 7 dimensions (market_gap x1.5, uniqueness x1.3, audience_demand x1.2, others x1.0). Round to 1 decimal.",\n    "verdict": "STRONG_GO (8-10) | CONDITIONAL_GO (6-7.9) | WEAK (4-5.9) | NO_GO (1-3.9)",\n    "verdict_reason": "2-3 sentences explaining the verdict with specific evidence from the analysis"\n  },\n  "overall_score": "1-10",\n  "one_line_summary": "One sentence summarizing approach and main gap"\n}\n\nReturn ONLY valid JSON, no markdown fences.`;

let analysis = null;
try {
  const aiResp = await httpReq({ method: 'POST', url: 'https://api.anthropic.com/v1/messages', headers: { 'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' }, body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 8000, system: systemPrompt, messages: [{ role: 'user', content: userPrompt }] }) });

  // Detect API-error response shapes BEFORE the JSON parse fallback masks
  // them. Anthropic returns { type: 'error', error: { type, message } } for
  // billing / auth / rate-limit failures. Without this guard, an empty
  // .content[0].text was being silently stored as { raw_text: '',
  // parse_error: true } with status='complete', and the dashboard rendered
  // a blank analysis page (real cause: out of credits).
  if (aiResp && (aiResp.type === 'error' || aiResp.error)) {
    const apiErr = aiResp.error?.message || aiResp.error?.type || aiResp.type || 'unknown anthropic error';
    await updateStatus('failed', { error: `Anthropic API error: ${apiErr}` });
    return [{ json: { error: apiErr } }];
  }

  const aiText = aiResp?.content?.[0]?.text || '';
  if (!aiText) {
    await updateStatus('failed', { error: 'Anthropic returned empty text. Response shape: ' + JSON.stringify(aiResp).slice(0, 400) });
    return [{ json: { error: 'empty_anthropic_response' } }];
  }

  const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try { analysis = JSON.parse(cleaned); } catch { analysis = { raw_text: aiText, parse_error: true }; }
} catch (e) {
  await updateStatus('failed', { error: 'Claude analysis failed: ' + e.message });
  return [{ json: { error: e.message } }];
}

// Add comment metadata to analysis
if (analysis && !analysis.parse_error) {
  analysis._meta = { comments_fetched: topComments.length, transcript_length: transcript.length };
}

// If Claude returned non-JSON, mark the row failed instead of complete so
// the dashboard surfaces the issue instead of rendering blank.
if (analysis?.parse_error) {
  await updateStatus('failed', { error: 'Claude returned non-JSON output. First 400 chars: ' + (analysis.raw_text || '').slice(0, 400), analysis });
  return [{ json: { analysis_id: analysisId, status: 'failed', reason: 'non_json_output' } }];
}

await updateStatus('complete', { analysis });
return [{ json: { analysis_id: analysisId, status: 'complete' } }];
